#include <bits/stdc++.h>
using namespace std;

const int N=100;

int n,m;
long long f[N][N];
int d[4][2]={{-2,1},{-1,2},{1,2},{2,1}};

int main(){
    scanf("%d%d",&n,&m);
    f[0][0]=1;
    for(int j=0;j<=m;j++)
        for(int i=0;i<=n;i++)
            for(int k=0;k<4;k++){
                int xx=i+d[k][0],yy=j+d[k][1];
                if(xx>=0 && yy>=0 && xx<=n && yy<=m)
                    f[xx][yy]+=f[i][j];
            }
    printf("%lld",f[n][m]);
    return 0;
}
